import React, { useEffect, useState } from 'react';

function StructuredSuiteConfig({ apiBase, isRunning, isInitialized, onRunStructuredSuite }) {
  const [suite, setSuite] = useState({
    suite_name: '',
    count: 0,
    errors: [],
    plan_summary: {},
    preview: []
  });

  const [summary, setSummary] = useState({
    total: 0,
    modules: {},
    families: {},
    execution_modes: {},
    automation_levels: {},
    priorities: {}
  });

  const [busy, setBusy] = useState(false);

  const [selectedModule, setSelectedModule] = useState('');
  const [selectedFamily, setSelectedFamily] = useState('');
  const [selectedMode, setSelectedMode] = useState('');
  const [selectedLevel, setSelectedLevel] = useState('');
  const [selectedPriority, setSelectedPriority] = useState('');
  const [limit, setLimit] = useState(10);

  const refresh = async () => {
    try {
      const res1 = await fetch(`${apiBase}/api/structured-suite`);
      const data1 = await res1.json();
      setSuite(data1);

      const res2 = await fetch(`${apiBase}/api/structured-suite/classification-summary`);
      const data2 = await res2.json();
      setSummary(data2);
    } catch (err) {
      console.error('Structured suite refresh failed:', err);
    }
  };

  useEffect(() => { refresh(); }, []);

  const onPick = async (e) => {
    const f = (e.target.files || [])[0];
    if (!f) return;

    setBusy(true);
    try {
      const fd = new FormData();
      fd.append('file', f);
      const res = await fetch(`${apiBase}/api/structured-suite/upload`, { method: 'POST', body: fd });
      await res.json();
      await refresh();
    } finally {
      setBusy(false);
      e.target.value = '';
    }
  };

  const handleRun = () => {
    const payload = {
      limit: Number(limit) || 10
    };

    if (selectedMode) payload.execution_modes = [selectedMode];
    if (selectedLevel) payload.automation_levels = [selectedLevel];
    if (selectedPriority) payload.priorities = [selectedPriority];

    // module/family filtering is frontend-side for now via scenario ids
    let preview = suite.preview || [];
    if (selectedModule) {
      preview = preview.filter(p => p.module === selectedModule);
    }
    if (selectedFamily) {
      preview = preview.filter(p => p.family === selectedFamily);
    }

    if (selectedModule || selectedFamily) {
      payload.scenario_ids = preview.slice(0, Number(limit) || 10).map(p => p.scenario_id);
    }

    onRunStructuredSuite(payload);
  };

  return (
    <div style={{ marginTop: '14px' }}>
      <h3 style={{ fontSize: '14px', fontWeight: 700, marginBottom: '10px', color: '#667eea' }}>
        Structured Scenario Workbook
      </h3>

      <input
        type="file"
        disabled={busy || isRunning}
        onChange={onPick}
        style={{ width: '100%', marginBottom: '10px' }}
        accept=".xlsx"
      />

      <div style={{ fontSize: '12px', color: '#a0aec0', marginBottom: '6px' }}>
        Loaded: {suite.count || 0} structured scenarios {suite.suite_name ? `(${suite.suite_name})` : ''}
      </div>

      {suite.errors && suite.errors.length > 0 && (
        <div style={{ background: '#742a2a', color: '#fed7d7', padding: '8px', borderRadius: '6px', fontSize: '12px', marginBottom: '10px' }}>
          {suite.errors.map((er, i) => <div key={i}>• {er}</div>)}
        </div>
      )}

      <div style={{ background: '#1a202c', padding: '10px', borderRadius: '8px', marginBottom: '10px', fontSize: '12px' }}>
        <div><strong>Total:</strong> {summary.total || 0}</div>
        <div><strong>Modules:</strong> {Object.keys(summary.modules || {}).length}</div>
        <div><strong>Families:</strong> {Object.keys(summary.families || {}).length}</div>
        <div><strong>Execution Modes:</strong> {Object.keys(summary.execution_modes || {}).length}</div>
      </div>

      <div style={{ background: '#1a202c', padding: '10px', borderRadius: '8px', marginBottom: '10px' }}>
        <div style={{ fontSize: '12px', fontWeight: 700, color: '#e2e8f0', marginBottom: '8px' }}>
          Run Filters
        </div>

        <div className="form-group">
          <label className="form-label">Module</label>
          <select className="form-input" value={selectedModule} onChange={(e) => setSelectedModule(e.target.value)}>
            <option value="">All</option>
            {Object.keys(summary.modules || {}).sort().map((m, i) => (
              <option key={i} value={m}>{m}</option>
            ))}
          </select>
        </div>

        <div className="form-group">
          <label className="form-label">Family</label>
          <select className="form-input" value={selectedFamily} onChange={(e) => setSelectedFamily(e.target.value)}>
            <option value="">All</option>
            {Object.keys(summary.families || {}).sort().map((f, i) => (
              <option key={i} value={f}>{f}</option>
            ))}
          </select>
        </div>

        <div className="form-group">
          <label className="form-label">Execution Mode</label>
          <select className="form-input" value={selectedMode} onChange={(e) => setSelectedMode(e.target.value)}>
            <option value="">All</option>
            {Object.keys(summary.execution_modes || {}).sort().map((m, i) => (
              <option key={i} value={m}>{m}</option>
            ))}
          </select>
        </div>

        <div className="form-group">
          <label className="form-label">Automation Level</label>
          <select className="form-input" value={selectedLevel} onChange={(e) => setSelectedLevel(e.target.value)}>
            <option value="">All</option>
            {Object.keys(summary.automation_levels || {}).sort().map((l, i) => (
              <option key={i} value={l}>{l}</option>
            ))}
          </select>
        </div>

        <div className="form-group">
          <label className="form-label">Priority</label>
          <select className="form-input" value={selectedPriority} onChange={(e) => setSelectedPriority(e.target.value)}>
            <option value="">All</option>
            {Object.keys(summary.priorities || {}).sort().map((p, i) => (
              <option key={i} value={p}>{p}</option>
            ))}
          </select>
        </div>

        <div className="form-group">
          <label className="form-label">Limit</label>
          <input
            type="number"
            className="form-input"
            value={limit}
            onChange={(e) => setLimit(e.target.value)}
            min="1"
            max="100"
          />
        </div>
      </div>

      <button
        className="btn btn-primary"
        disabled={!isInitialized || isRunning || busy || !(suite.count > 0)}
        onClick={handleRun}
        style={{ width: '100%' }}
      >
        Run Structured Suite
      </button>

      <button
        className="btn btn-sm"
        style={{ width: '100%', marginTop: '8px', background: '#2d3748', color: '#a0aec0' }}
        onClick={refresh}
        disabled={busy || isRunning}
      >
        Refresh Structured Suite
      </button>
    </div>
  );
}

export default StructuredSuiteConfig;
